INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '21d35d93-61f8-49a5-9926-c02e35cc811b',
  '00000000-0000-0000-0000-000000000001',
  $escape$WebGPU — Mastering Vulkan's Explicit API with Command Buffers and Render Passes$escape$,
  $escape$WebGPU's Vulkan-inspired API requires manual management of command buffers, render passes, and synchronization. This explicit approach can be verbose, but offers fine-grained control over graphics rendering. When creating a WebGPU render pass, you must specify the color and depth/stencil attachments, as well as the load and store operations for each attachment. Command buffers are used to record a sequence of rendering commands, which are then submitted to the GPU for execution. Synchronization primitives, such as fences and semaphores, ensure that commands are executed in the correct order.$escape$,
  $escape$const commandBuffer = device.createCommandBuffer();
const renderPass = device.createRenderPass({
  colorAttachments: [{
    loadValue: { r: 0.0, g: 0.0, b: 0.0, a: 1.0 }
  }],
  depthStencilAttachment: {
    loadValue: { depth: 1.0, stencil: 0 }
  }
});
commandBuffer.beginRenderPass(renderPass);$escape$,
  $escape$javascript$escape$,
