INSERT INTO bytes.bytes (id, author_id, title, body, code_snippet, language, embedding, type, is_active, created_at, updated_at) VALUES (
  '2da6193e-dfe7-464b-89e6-4a1f88ec37b2',
  '00000000-0000-0000-0000-000000000001',
  $escape$WebGPU - Leveraging PipelineStatistics for Real-Time Post-Processing$escape$,
  $escape$To optimize post-processing effects in WebGPU, analyze pipeline statistics using `device.getPipelineStatistics`. This API provides insights into compute and graphics performance, helping you identify bottlenecks. For instance, bloom effects often require multiple render passes, making them a prime target for optimization. By monitoring pipeline statistics, you can adjust parameters like shader dispatch size, texture sampling rates, and render target formats to achieve a balance between visual quality and performance. This enables efficient rendering of complex post-processing effects like depth of field, tone mapping, and screen-space ambient occlusion.$escape$,
  $escape$device.getPipelineStatistics()
   .then((stats) => {
       const computeStats = stats.computeStatistics;
       const graphicsStats = stats.graphicsStatistics;
       // Analyze statistics to inform decisions on shader dispatch size, texture sampling rates, etc.
   })$escape$,
  $escape$typescript$escape$,
